import sys, os
sys.path.insert(0, os.getcwd())
from catalog.cache import CatalogCache

class MockStore:
    def __init__(self):
        self.data = {}
        self.ttls = {}
    def get(self, key):
        return self.data.get(key)
    def set(self, key, value, ttl):
        self.data[key] = value
        self.ttls[key] = ttl

class MockDB:
    def fetch_product(self, pid):
        return {'id': pid, 'name': f'Product {pid}'}

def test_ttl_has_jitter():
    store = MockStore()
    db = MockDB()
    cache = CatalogCache(store, db, default_ttl=3600)
    # Warm multiple products
    cache.warm_cache(list(range(100)))
    ttls = list(store.ttls.values())
    unique_ttls = set(ttls)
    # With jitter, we should have multiple different TTLs
    assert len(unique_ttls) > 1, f'All {len(ttls)} keys have same TTL ({ttls[0]}s) — stampede risk!'

def test_get_product_works():
    store = MockStore()
    db = MockDB()
    cache = CatalogCache(store, db)
    product = cache.get_product(42)
    assert product['id'] == 42

