import time
import random

class CatalogCache:
    def __init__(self, store, db, default_ttl=3600, jitter_pct=0.2):
        self.store = store
        self.db = db
        self.default_ttl = default_ttl
        self.jitter_pct = jitter_pct

    def _jittered_ttl(self):
        jitter = int(self.default_ttl * self.jitter_pct * random.random())
        return self.default_ttl + jitter

    def get_product(self, product_id):
        key = f'product:{product_id}'
        cached = self.store.get(key)
        if cached is not None:
            return cached
        product = self.db.fetch_product(product_id)
        self.store.set(key, product, ttl=self._jittered_ttl())
        return product

    def warm_cache(self, product_ids):
        for pid in product_ids:
            product = self.db.fetch_product(pid)
            self.store.set(f'product:{pid}', product, ttl=self._jittered_ttl())
